#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define LOG_DIVISIONS 10
#define DIVISIONS (1 << LOG_DIVISIONS)

__constant int constStartAddr[DIVISIONS + 1];
__constant int finalStartAddr[DIVISIONS + 1];
__constant int nullElems[DIVISIONS];

inline float4 sortElem(float4 r) {
    float4 nr;

    nr.x = (r.x > r.y) ? r.y : r.x;
    nr.y = (r.y > r.x) ? r.y : r.x;
    nr.z = (r.z > r.w) ? r.w : r.z;
    nr.w = (r.w > r.z) ? r.w : r.z;

    r.x = (nr.x > nr.z) ? nr.z : nr.x;
    r.y = (nr.y > nr.w) ? nr.w : nr.y;
    r.z = (nr.z > nr.x) ? nr.z : nr.x;
    r.w = (nr.w > nr.y) ? nr.w : nr.y;

    nr.x = r.x;
    nr.y = (r.y > r.z) ? r.z : r.y;
    nr.z = (r.z > r.y) ? r.z : r.y;
    nr.w = r.w;
    return nr;
}

inline float4 getLowest(float4 a, float4 b)
{
    a.x = (a.x < b.w) ? a.x : b.w;
    a.y = (a.y < b.z) ? a.y : b.z;
    a.z = (a.z < b.y) ? a.z : b.y;
    a.w = (a.w < b.x) ? a.w : b.x;
    return a;
}

inline float4 getHighest(float4 a, float4 b)
{
    b.x = (a.w >= b.x) ? a.w : b.x;
    b.y = (a.z >= b.y) ? a.z : b.y;
    b.z = (a.y >= b.z) ? a.y : b.z;
    b.w = (a.x >= b.w) ? a.x : b.w;
    return b;
}

__kernel void mergeSortFirst(__read_only image1d_buffer_t tex, __global float4 *result, int listsize)
{
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int idx = bx * get_local_size(0) + tx;
    if (idx < listsize / 4) {
        float4 r = read_imagef(tex, CLK_ADDRESS_NONE | CLK_FILTER_NEAREST, idx);
        result[idx] = sortElem(r);
    }
}

__kernel void mergeSortPass(__read_only image1d_buffer_t tex, __global float4 *result, int nrElems, int threadsPerDiv)
{
    int tid = get_global_id(0);

    int division = tid / threadsPerDiv;
    if (division >= DIVISIONS) return;

    int int_tid = tid - division * threadsPerDiv;
    int Astart = constStartAddr[division] + int_tid * nrElems;

    int Bstart = Astart + nrElems / 2;
    __global float4 *resStart = &result[Astart];

    if (Astart >= constStartAddr[division + 1])
        return;
    if (Bstart >= constStartAddr[division + 1]) {
        for (int i = 0; i < (constStartAddr[division + 1] - Astart); i++) {
            resStart[i] = read_imagef(tex, CLK_ADDRESS_NONE | CLK_FILTER_NEAREST, Astart + i);
        }
        return;
    }

    int aidx = 0;
    int bidx = 0;
    int outidx = 0;
    float4 a = read_imagef(tex, CLK_ADDRESS_NONE | CLK_FILTER_NEAREST, Astart + aidx);
    float4 b = read_imagef(tex, CLK_ADDRESS_NONE | CLK_FILTER_NEAREST, Bstart + bidx);

    while (true) {
        float4 nextA = read_imagef(tex, CLK_ADDRESS_NONE | CLK_FILTER_NEAREST, Astart + aidx + 1);
        float4 nextB = read_imagef(tex, CLK_ADDRESS_NONE | CLK_FILTER_NEAREST, Bstart + bidx + 1);

        float4 na = getLowest(a, b);
        float4 nb = getHighest(a, b);
        a = sortElem(na);
        b = sortElem(nb);

        resStart[outidx++] = a;

        bool elemsLeftInA = (aidx + 1 < nrElems / 2);
        bool elemsLeftInB = (bidx + 1 < nrElems / 2) && (Bstart + bidx + 1 < constStartAddr[division + 1]);

        if (elemsLeftInA) {
            if (elemsLeftInB) {
                if (nextA.x < nextB.x) {
                    aidx += 1; a = nextA;
                }
                else {
                    bidx += 1; a = nextB;
                }
            }
            else {
                aidx += 1; a = nextA;
            }
        }
        else {
            if (elemsLeftInB) {
                bidx += 1; a = nextB;
            }
            else {
                break;
            }
        }
    }
    resStart[outidx++] = b;
}

__kernel void mergepack(__global float *orig, __global float *result)
{
    int idx = get_local_id(0) + get_group_id(0) * get_local_size(0);
    int division = get_group_id(1);

    if ((finalStartAddr[division] + idx) >= finalStartAddr[division + 1]) return;
    result[finalStartAddr[division] + idx] = orig[constStartAddr[division] * 4 + nullElems[division] + idx];
}
